#include<bits/stdc++.h>
using namespace std;
int n,m;
vector<pair<int,int>> mp[100010];
double dp[100010];
int in[100010],in1[100010];
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[v].push_back(make_pair(u,w));
        in[u]++;
        in1[u]++;
    }
    queue<int> q;
    q.push(n);
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(auto i:mp[t])
        {
            int v=i.first,val=i.second;
            dp[v]+=(dp[t]+val)*1.0/in1[v];
            in[v]--;
            if(in[v]==0)
            {
                q.push(v);
            }
        }
    }
    printf("%.2lf",dp[1]);
    return 0;
}
